import React, { useState } from "react";
import SplashScreen from "./screens/SplashScreen";
import SignInScreen from "./screens/SignInScreen";
import SignUpScreen from "./screens/SignUpScreen";
import Dashboard from "./screens/Dashboard";

import HomeScreen from "./screens/HomeScreen";
import GoalsScreen from "./screens/GoalsScreen";
import LoansScreen from "./screens/LoansScreen";
import ProfileScreen from "./screens/ProfileScreen";

import TransactionHistoryScreen from "./screens/TransactionHistoryScreen";
import DepositScreen from "./screens/DepositScreen";
import WithdrawScreen from "./screens/WithdrawalScreen";
import SavingsDepositScreen from "./screens/SavingsDepositScreen";
import SavingsWithdrawScreen from "./screens/SavingsWithdrawalScreen";

export default function App() {
  const [currentScreen, setCurrentScreen] = useState("splash");
  const [dashboardTab, setDashboardTab] = useState("home");
  const [modal, setModal] = useState(null); // "deposit", "withdraw", "savingsDeposit", "savingsWithdraw", "transactions"
  const [balance, setBalance] = useState(5000);
  const [savingsBalance, setSavingsBalance] = useState(1500);
  const [transactions, setTransactions] = useState([
    { id: 1, title: "Initial deposit", amount: 5000, type: "deposit", date: "Jan 25, 2026" },
  ]);
  const [userName, setUserName] = useState("Faith Bode");

  const handleDeposit = (amount) => {
    setBalance(balance + amount);
    setTransactions([{ id: Date.now(), title: "Deposit", amount, type: "deposit", date: new Date().toLocaleDateString() }, ...transactions]);
    setModal(null);
  };

  const handleWithdraw = (amount) => {
    setBalance(balance - amount);
    setTransactions([{ id: Date.now(), title: "Withdraw", amount, type: "withdraw", date: new Date().toLocaleDateString() }, ...transactions]);
    setModal(null);
  };

  const handleSavingsDeposit = (amount) => {
    if (amount > balance) {
      alert("Insufficient balance for savings deposit");
      return;
    }
    setBalance(balance - amount);
    setSavingsBalance(savingsBalance + amount);
    setTransactions([{ id: Date.now(), title: "Savings Deposit", amount, type: "deposit", date: new Date().toLocaleDateString() }, ...transactions]);
    setModal(null);
  };

  const handleSavingsWithdraw = (amount) => {
    if (amount > savingsBalance) {
      alert("Insufficient savings balance");
      return;
    }
    setBalance(balance + amount);
    setSavingsBalance(savingsBalance - amount);
    setTransactions([{ id: Date.now(), title: "Savings Withdraw", amount, type: "withdraw", date: new Date().toLocaleDateString() }, ...transactions]);
    setModal(null);
  };

  const getGreeting = () => {
    const hour = new Date().getHours();
    if (hour < 12) return "Good Morning";
    if (hour < 18) return "Good Afternoon";
    return "Good Evening";
  };

  // Render Splash / SignIn / SignUp
  if (currentScreen === "splash") return <SplashScreen onFinish={() => setCurrentScreen("signIn")} />;
  if (currentScreen === "signIn") return <SignInScreen onSignIn={() => setCurrentScreen("dashboard")} onSwitchSignUp={() => setCurrentScreen("signUp")} />;
  if (currentScreen === "signUp") return <SignUpScreen onSignUp={() => setCurrentScreen("dashboard")} onSwitchSignIn={() => setCurrentScreen("signIn")} />;

  // Render Dashboard with tabs
  return (
    <div className="min-h-screen bg-gray-50 flex flex-col">
      <div className="flex-1 overflow-y-auto">
        {modal === "deposit" && <DepositScreen onDeposit={handleDeposit} />}
        {modal === "withdraw" && <WithdrawScreen balance={balance} onWithdraw={handleWithdraw} />}
        {modal === "savingsDeposit" && <SavingsDepositScreen onDeposit={handleSavingsDeposit} />}
        {modal === "savingsWithdraw" && <SavingsWithdrawScreen savingsBalance={savingsBalance} onWithdraw={handleSavingsWithdraw} />}
        {modal === "transactions" && <TransactionHistoryScreen transactions={transactions} />}

        {!modal && dashboardTab === "home" && <HomeScreen balance={balance} userName={userName} transactions={transactions} getGreeting={getGreeting} setModal={setModal} />}
        {!modal && dashboardTab === "goals" && <GoalsScreen />}
        {!modal && dashboardTab === "loans" && <LoansScreen />}
        {!modal && dashboardTab === "profile" && <ProfileScreen userName={userName} balance={balance} savingsBalance={savingsBalance} />}
      </div>

      {/* Bottom Navigation */}
      <nav className="bg-white shadow-t border-t border-gray-200 fixed bottom-0 w-full flex justify-around py-3">
        {["home", "goals", "loans", "profile"].map((tab) => (
          <button
            key={tab}
            onClick={() => setDashboardTab(tab)}
            className={`flex-1 text-center py-2 ${dashboardTab === tab ? "text-emerald-600 font-bold" : "text-gray-500"}`}
          >
            {tab.charAt(0).toUpperCase() + tab.slice(1)}
          </button>
        ))}
      </nav>
    </div>
  );
}
